import{_ as a,o as e,c as o,ae as t}from"./chunks/framework.Dzr56EFm.js";const A=JSON.parse('{"title":"大厂战略 - 2026-04-10","description":"","frontmatter":{"date":"2026-04-10T00:00:00.000Z","category":"BigTech"},"headers":[],"relativePath":"daily/2026-04-10-bigtech.md","filePath":"daily/2026-04-10-bigtech.md"}'),n={name:"daily/2026-04-10-bigtech.md"};function s(p,r,l,i,g,h){return e(),o("div",null,[...r[0]||(r[0]=[t('<h1 id="大厂战略-2026-04-10" tabindex="-1">大厂战略 - 2026-04-10 <a class="header-anchor" href="#大厂战略-2026-04-10" aria-label="Permalink to &quot;大厂战略 - 2026-04-10&quot;">​</a></h1><blockquote><p>OpenAI、Google、Apple、Microsoft、Meta、Amazon战略</p></blockquote><h2 id="今日概览" tabindex="-1">今日概览 <a class="header-anchor" href="#今日概览" aria-label="Permalink to &quot;今日概览&quot;">​</a></h2><p>今日AI领域大厂战略资讯汇总：</p><ol><li>制定AI战略需在四个核心领域进行结构化规划。</li><li>亚马逊启动6800万美元人工智能博士奖学金项目，资助100多名博士生。</li><li>微软AI提升商业销售策略。</li><li>微软发布2025年未来工作报告，提出负责任AI组织成熟度模型。</li><li>亚马逊宣布2026年Nova AI挑战赛，聚焦可信软件代理AI。</li></ol><p>最值得关注：亚马逊的人工智能博士奖学金项目和微软的未来工作报告。</p><hr><h3 id="_1-制定你的ai战略-云采用框架" tabindex="-1">1. 制定你的AI战略 - 云采用框架 <a class="header-anchor" href="#_1-制定你的ai战略-云采用框架" aria-label="Permalink to &quot;1. 制定你的AI战略 - 云采用框架&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://learn.microsoft.com/en-us/azure/cloud-adoption-framework/scenarios/ai/strategy" target="_blank" rel="noreferrer">Create your AI strategy - Cloud Adoption Framework | Microsoft Learn</a></p><p><strong>一句话摘要</strong>: 规划AI战略，需在四个核心领域进行结构化规划。</p><p><strong>能解决什么问题</strong>: 帮助组织识别AI用例，选择技术，建立数据治理，实施负责任的AI。</p><p><strong>产品应用</strong>: 适用于各规模组织，通过微软AI技术实现业务价值。</p><p><strong>示例场景</strong>: Contoso公司使用AI预测业务数据和产品库存管理。</p><hr><h3 id="_2-亚马逊启动6800万美元人工智能博士奖学金项目" tabindex="-1">2. 亚马逊启动6800万美元人工智能博士奖学金项目 <a class="header-anchor" href="#_2-亚马逊启动6800万美元人工智能博士奖学金项目" aria-label="Permalink to &quot;2. 亚马逊启动6800万美元人工智能博士奖学金项目&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.amazon.science/news/amazon-launches-68-million-ai-phd-fellowship-program" target="_blank" rel="noreferrer">Amazon launches $68 million AI PhD Fellowship program</a></p><p><strong>一句话摘要</strong>: 亚马逊资助100多名博士生研究人工智能核心领域。</p><p><strong>能解决什么问题</strong>: 推动人工智能领域创新，解决实际AI问题。</p><p><strong>产品应用</strong>: 可应用于产品开发，通过合作提升AI技术。</p><p><strong>示例场景</strong>: 与亚马逊工程师合作，研发自然语言处理技术。</p><hr><h3 id="_3-商业与企业战略中的人工智能-微软ai" tabindex="-1">3. 商业与企业战略中的人工智能 | 微软AI <a class="header-anchor" href="#_3-商业与企业战略中的人工智能-微软ai" aria-label="Permalink to &quot;3. 商业与企业战略中的人工智能 | 微软AI&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.microsoft.com/en-us/ai/ai-business-value-and-benefits" target="_blank" rel="noreferrer">AI in Business and Corporate Strategy | Microsoft AI</a></p><p><strong>一句话摘要</strong>: 微软AI通过高级工具显著提升销售策略和成果。</p><p><strong>能解决什么问题</strong>: 解决销售过程中的重复性工作和个性化客户互动问题。</p><p><strong>产品应用</strong>: 可以应用到实际产品中，通过自动化和数据分析提升效率。</p><p><strong>示例场景</strong>: 使用AI自动化处理电子邮件和数据可视化。</p><hr><h3 id="_4-微软2025年未来工作报告" tabindex="-1">4. 微软2025年未来工作报告 <a class="header-anchor" href="#_4-微软2025年未来工作报告" aria-label="Permalink to &quot;4. 微软2025年未来工作报告&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.microsoft.com/en-us/research/wp-content/uploads/2025/12/New-Future-Of-Work-Report-2025.pdf" target="_blank" rel="noreferrer">[PDF] Microsoft New Future of Work Report 2025</a></p><p><strong>一句话摘要</strong>: 微软研究报告提出负责任AI组织成熟度模型。</p><p><strong>能解决什么问题</strong>: 组织变革中AI能力建设和采纳的挑战。</p><p><strong>产品应用</strong>: 可应用于企业规划负责任AI战略和实践。</p><p><strong>示例场景</strong>: 企业使用RAI-OMM模型指导AI战略规划。</p><hr><h3 id="_5-亚马逊宣布2026年亚马逊nova-ai挑战赛-可信软件代理赛道" tabindex="-1">5. 亚马逊宣布2026年亚马逊Nova AI挑战赛：可信软件代理赛道 <a class="header-anchor" href="#_5-亚马逊宣布2026年亚马逊nova-ai挑战赛-可信软件代理赛道" aria-label="Permalink to &quot;5. 亚马逊宣布2026年亚马逊Nova AI挑战赛：可信软件代理赛道&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.amazon.science/nova-ai-challenge/amazon-announces-the-2026-amazon-nova-ai-challenge-trusted-software-agents" target="_blank" rel="noreferrer">Amazon announces the 2026 Amazon Nova AI Challenge: Trusted Software Agents track - Amazon Science</a></p><p><strong>一句话摘要</strong>: 亚马逊Nova AI挑战赛聚焦于推进可信、有用的软件工程代理AI。</p><p><strong>能解决什么问题</strong>: 解决多步骤软件开发任务中模型性能提升与安全维护的平衡问题。</p><p><strong>产品应用</strong>: 可以应用于实际软件开发，通过构建代理处理复杂工程任务。</p><p><strong>示例场景</strong>: 构建AI代理自动完成软件测试和代码审查。</p><hr><h3 id="_6-人工智能-ai-亚马逊科学" tabindex="-1">6. 人工智能（AI）- 亚马逊科学 <a class="header-anchor" href="#_6-人工智能-ai-亚马逊科学" aria-label="Permalink to &quot;6. 人工智能（AI）- 亚马逊科学&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.amazon.science/tag/artificial-intelligence" target="_blank" rel="noreferrer">Artificial intelligence (AI) - Amazon Science</a></p><p><strong>一句话摘要</strong>: 亚马逊广告团队利用AI技术革新广告体验。</p><p><strong>能解决什么问题</strong>: 解决广告效率低下和个性化不足的问题。</p><p><strong>产品应用</strong>: 应用于亚马逊广告，通过AI优化广告投放和客户体验。</p><p><strong>示例场景</strong>: 通过AI技术为顾客提供定制化产品发现体验。</p><hr><h3 id="_7-亚马逊科学2025年秋季ai信息安全提案征集" tabindex="-1">7. 亚马逊科学2025年秋季AI信息安全提案征集 <a class="header-anchor" href="#_7-亚马逊科学2025年秋季ai信息安全提案征集" aria-label="Permalink to &quot;7. 亚马逊科学2025年秋季AI信息安全提案征集&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.amazon.science/research-awards/call-for-proposals/ai-for-information-security-call-for-proposals-fall-2025" target="_blank" rel="noreferrer">AI for Information Security call for proposals - Fall 2025 - Amazon Science</a></p><p><strong>一句话摘要</strong>: 亚马逊AGI实验室开发AI代理基础能力，推出Nova Act AI模型。</p><p><strong>能解决什么问题</strong>: 提高AI/ML系统性能，实现客户生产力和满意度提升。</p><p><strong>产品应用</strong>: 应用于亚马逊健康组织，包括亚马逊药房和One Medical。</p><p><strong>示例场景</strong>: 亚马逊药房利用AI模型优化药物配送流程。</p><hr><h3 id="_8-在苹果平台上发现机器学习和ai框架-wwdc25-视频-apple-developer" tabindex="-1">8. 在苹果平台上发现机器学习和AI框架 - WWDC25 - 视频 - Apple Developer <a class="header-anchor" href="#_8-在苹果平台上发现机器学习和ai框架-wwdc25-视频-apple-developer" aria-label="Permalink to &quot;8. 在苹果平台上发现机器学习和AI框架 - WWDC25 - 视频 - Apple Developer&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://developer.apple.com/videos/play/wwdc2025/360/" target="_blank" rel="noreferrer">Discover machine learning &amp; AI frameworks on Apple platforms - WWDC25 - Videos - Apple Developer</a></p><p><strong>一句话摘要</strong>: 苹果推出MLX框架，支持在苹果设备上高效训练和部署AI模型。</p><p><strong>能解决什么问题</strong>: 解决在苹果设备上进行机器学习和AI模型训练和部署的需求。</p><p><strong>产品应用</strong>: 可以应用到实际产品中，通过MLX框架和APIs实现AI功能。</p><p><strong>示例场景</strong>: 使用MLX框架在iPhone上训练和部署语言模型。</p><hr><h3 id="_9-亚马逊研究奖-ara" tabindex="-1">9. 亚马逊研究奖（ARA） <a class="header-anchor" href="#_9-亚马逊研究奖-ara" aria-label="Permalink to &quot;9. 亚马逊研究奖（ARA）&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.amazon.science/research-awards" target="_blank" rel="noreferrer">Amazon Research Awards (ARA)</a></p><p><strong>一句话摘要</strong>: 亚马逊招募科学家推动负责任的AI对话助手发展。</p><p><strong>能解决什么问题</strong>: 确保Alexa在全球范围内提供安全、可信的体验。</p><p><strong>产品应用</strong>: 应用于Alexa+，通过负责任的AI解决方案提升用户体验。</p><p><strong>示例场景</strong>: 用户通过Alexa+获取安全、个性化的信息和建议。</p><hr><h3 id="_10-负责任的人工智能原则与方法-微软人工智能" tabindex="-1">10. 负责任的人工智能原则与方法 | 微软人工智能 <a class="header-anchor" href="#_10-负责任的人工智能原则与方法-微软人工智能" aria-label="Permalink to &quot;10. 负责任的人工智能原则与方法 | 微软人工智能&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.microsoft.com/en-us/ai/principles-and-approach" target="_blank" rel="noreferrer">Responsible AI Principles and Approach</a></p><p><strong>一句话摘要</strong>: 微软提出了负责任的人工智能原则和方法。</p><p><strong>能解决什么问题</strong>: 确保人工智能技术的发展符合伦理和社会责任。</p><p><strong>产品应用</strong>: 可以应用到实际产品中，指导AI技术的开发和使用。</p><p><strong>示例场景</strong>: 在金融领域使用AI进行风险评估和合规性检查。</p><hr>',77)])])}const d=a(n,[["render",s]]);export{A as __pageData,d as default};
